          </ToggleGroup>
        </Fieldset>
        <Fieldset>
          <Fieldset.Legend>
            Farger
            <code data-size="xs">(data-color)</code>
          </Fieldset.Legend>
          <ToggleGroup value={colorScheme} onChange={setColorScheme}>
            {colorSchemes.map((tm) => (
              <ToggleGroup.Item key={tm} value={tm}>
                {tm}
              </ToggleGroup.Item>
            ))}
          </ToggleGroup>
        </Fieldset>
      </div>
      <Showcase
        data-size={size}
        data-color={colorScheme}
