      <ValidationMessage {...validationMessageProps} />
    </Fieldset>
  );
};

const Controlled = (args, context) => {
  const choices: Choices = {
    barnehage: { label: 'Barnehage' },
    grunnskole: { label: 'Grunnskole' },
    videregaende: { label: 'Videregående' },
  };
  const { getCheckboxProps, validationMessageProps, value, setValue } = useCheckboxGroup({
    name: 'my-controlled',
    value: ['barnehage', 'videregaende'],
    ...args,
  });

  const toggle = (haystack: string[], needle: string) =>
    haystack.includes(needle) ? haystack.filter((v) => v !== needle) : haystack.concat(needle);

  const isFiltered = value.length > 0;
  return (
    <>
      <Fieldset>
        <Fieldset.Legend>Utdanningsnivå</Fieldset.Legend>
        {Object.entries(choices).map(([v, { label }]) => (
          <Checkbox key={v} id={`${context.id}-${v}`} label={label} {...getCheckboxProps(v)} />
        ))}
      </Fieldset>
      <ValidationMessage {...validationMessageProps} />
      <Divider />
      <Paragraph>(Annet innhold)</Paragraph>
      <Divider />
      <div style={{ display: 'flex', gap: 'var(--ds-size-2)' }}>
        <Paragraph>{isFiltered ? 'Viser innhold for:' : 'Viser alt innhold'}</Paragraph>
        {isFiltered &&
          value.map((v) => (
            <Chip.Removable key={v} aria-label={`Slett ${choices[v].label}`} onClick={() => setValue(toggle(value, v))}>
              {choices[v].label}
            </Chip.Removable>
          ))}
      </div>
      {isFiltered && (
        <Button style={{ width: 'fit-content' }} variant="outline" onClick={() => setValue([])}>
          Tøm filtre
        </Button>
      )}
    </>
  );
};

const ReadOnly = (args) => {
  const { getCheckboxProps, validationMessageProps } = useCheckboxGroup({
    value: ['epost'],
    ...args,
  });

  return (
    <Fieldset>
      <Fieldset.Legend>Hvordan vil du helst at vi skal kontakte deg?</Fieldset.Legend>
