const InTableWithPagination = (args) => {
  const itemsPerPage = 3;
  const [currentPage, setCurrentPage] = useState(1);

  const { getCheckboxProps } = useCheckboxGroup({
    ...args,
  });

  const totalPages = Math.ceil(tableData.length / itemsPerPage);

  const pagination = usePagination({
    currentPage,
    setCurrentPage,
    totalPages,
    showPages: totalPages,
  });

  // Compute the slice of users to display on the current page
  const currentData = useMemo(() => {
    const startIndex = (currentPage - 1) * itemsPerPage;
    return tableData.slice(startIndex, startIndex + itemsPerPage);
  }, [currentPage]);

  return (
    <div>
      <Table>
        <Table.Head>
          <Table.Row>
            <Table.HeaderCell>
              <Checkbox
                aria-label="Select all"
                {...getCheckboxProps({
                  allowIndeterminate: true,
                  value: 'all',
                })}
              />
            </Table.HeaderCell>
            <Table.HeaderCell>Navn</Table.HeaderCell>
            <Table.HeaderCell>Epost</Table.HeaderCell>
            <Table.HeaderCell>Telefon</Table.HeaderCell>
          </Table.Row>
        </Table.Head>
        <Table.Body>
          {currentData.map((user) => (
            <Table.Row key={user.id}>
              <Table.Cell>
                <Checkbox
                  aria-label={'Check ' + user.id}
                  {...getCheckboxProps({
                    value: user.id.toString(),
                  })}
                />
              </Table.Cell>
              <Table.Cell>{user.navn}</Table.Cell>
              <Table.Cell>{user.epost}</Table.Cell>
              <Table.Cell>{user.telefon}</Table.Cell>
            </Table.Row>
          ))}
        </Table.Body>
      </Table>
      <Pagination>
        <Pagination.List>
          <Pagination.Item>
            <Pagination.Button {...pagination.prevButtonProps}>Forrige</Pagination.Button>
          </Pagination.Item>
          {pagination.pages.map(({ itemKey, buttonProps, page }) => (
            <Pagination.Item key={itemKey}>
              {typeof page === 'number' && (
                <Pagination.Button {...buttonProps} aria-label={`Side ${page}`}>
                  {page}
                </Pagination.Button>
              )}
            </Pagination.Item>
          ))}
          <Pagination.Item>
            <Pagination.Button {...pagination.nextButtonProps}>Neste</Pagination.Button>
          </Pagination.Item>
        </Pagination.List>
      </Pagination>
    </div>
  );
};

